import React, { useState, useEffect, useCallback } from 'react';
import { useAuth } from '../contexts/AuthContext';
import { authAPI, studentAPI, facultyAPI, courseAPI, gradeAPI, examinationAPI, attendanceAPI, feeAPI, examRegistrationAPI } from '../services/api';
import { useNavigate } from 'react-router-dom';

const Dashboard = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [stats, setStats] = useState({
    // Core Metrics
    totalStudents: 0,
    totalFaculty: 0,
    totalCourses: 0,
    totalDepartments: 0,
    activeStudents: 0,
    recentEnrollments: 0,
    totalRevenue: 0,
    pendingFees: 0,

    // Academic Metrics
    averageGPA: 0,
    totalGrades: 0,
    upcomingExams: 0,
    completedExams: 0,
    averageAttendance: 0,
    teachingLoad: 0,

    // Financial Metrics
    monthlyRevenue: 0,
    pendingAmount: 0,
    collectedFees: 0,
    scholarshipAmount: 0,

    // System Metrics
    activeUsers: 0,
    systemUptime: 0,
    storageUsed: 0,
    apiCalls: 0,

    // Performance Metrics
    studentSatisfaction: 0,
    facultySatisfaction: 0,
    courseCompletion: 0,
    placementRate: 0,

    // Recent Data
    recentActivities: [],
    topPerformers: [],
    recentEnrollmentsList: [],
    upcomingEvents: [],

    // Department Analytics
    departmentStats: [],
    courseAnalytics: [],
    facultyPerformance: [],

    // View Mode
    viewMode: 'overview' // 'overview', 'academic', 'financial', 'analytics', 'users'
  });
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [selectedPeriod, setSelectedPeriod] = useState('month');

  const handleAddStudent = () => {
