      // Course Analytics
      const courseAnalytics = courses.map(course => ({
        name: course.name,
        code: course.code,
        students: students.filter(s => s.courseId === course.id).length,
        faculty: course.faculty?.firstName + ' ' + course.faculty?.lastName,
        credits: course.credits,
        status: course.status
